      setTimeLeft(prev => Math.max(0, prev - 1));
    }, 1000);

    return () => clearInterval(timer);
  }, [view, mode]);

  // Timer Expiry Effect
  useEffect(() => {
    if (timeLeft === 0 && (view === 'playing' || view === 'review') && mode !== 'practice') {
