                  </div>

                  {selectedGroups.length > 0 && (
                    <div className="flex flex-wrap gap-2 p-4 bg-slate-50 border border-slate-200 rounded-2xl max-h-32 overflow-y-auto custom-scrollbar shadow-inner">
                      {selectedGroups.map(group => (
