import React, { useState, useEffect, useMemo } from 'react';
import Header from './components/Header';
import Flashcards from './components/Flashcards';
import Quiz from './components/Quiz';
import QuestionList from './components/QuestionList';
import { AppMode, Question } from './types';
import { questions as systemQuestions } from './hooks/data';
import { questions as skeletonQuestions } from './hooks/data_skeleton';
import { questions as ch10Questions } from './hooks/data_ch10';
import { questions as ch11Concepts } from './hooks/data_ch11_concepts';
import { questions as ch11Diagrams } from './hooks/data_ch11_diagrams';
import { questions as chapterAllQuestions } from './hooks/data_chapter_all';
import { questions as customFixQuestions } from './hooks/data_custom_fixes';
import { ShieldCheck, DatabaseZap, Trash2 } from 'lucide-react';

const App: React.FC = () => {
  const [currentMode, setCurrentMode] = useState<AppMode>(AppMode.FLASHCARDS);
  const [isSyncing, setIsSyncing] = useState(false);

  // PRIMARY DATA VAULT: Loads user modifications from local storage (import/export only)
  const [userVault, setUserVault] = useState<Question[]>(() => {
    try {
      const saved = localStorage.getItem('anatomy_ultimate_vault_v4');
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      console.error("Critical: Data Vault Access Denied", e);
      return [];
    }
  });

  // AUTO-PERSISTENCE: Every change to the vault is instantly locked into storage
  useEffect(() => {
    localStorage.setItem('anatomy_ultimate_vault_v4', JSON.stringify(userVault));

    if (userVault.length > 0) {
        // UI Feedback for Syncing
        setIsSyncing(true);
        const timer = setTimeout(() => setIsSyncing(false), 1200);
        return () => clearTimeout(timer);
    }
  }, [userVault]);

  // KNOWLEDGE BASE COMPILER: Merges system data with user data
  const allQuestions = useMemo(() => {

    const uniqueQuestions: Question[] = [];
    const seenIds = new Set<string>();

    // 1. Add User Vault (Highest Priority)
    userVault.forEach(q => {
        uniqueQuestions.push(q);
        seenIds.add(q.id);
    });

    // 2. Add Specialized/Fixed Data (High Priority - Overrides System Data)
    const specializedSources = [
        customFixQuestions,  // Custom Fixes (Ch4 Tissues inside Ch10) - HIGHEST SYSTEM PRIORITY
        chapterAllQuestions, // "Chapter ALL" Fixes (Ch6 diagrams with options)
        ch10Questions,       // Ch10 Specialized
        ch11Diagrams,        // Ch11 Diagrams
        ch11Concepts,        // Ch11 Concepts
        skeletonQuestions    // Skeleton Specialized
    ];

    specializedSources.flat().forEach(q => {
        if (!seenIds.has(q.id)) {
            uniqueQuestions.push(q);
            seenIds.add(q.id);
        }
    });

    // 3. Add System Data (Lowest Priority - Base Content)
    systemQuestions.forEach(q => {
        if (!seenIds.has(q.id)) {
            uniqueQuestions.push(q);
            seenIds.add(q.id);
        }
    });

    return uniqueQuestions;
  }, [userVault]);

  const exportVault = () => {
    const dataStr = JSON.stringify(userVault, null, 2);
    const dataUri = 'data:application/json;charset=utf-8,' + encodeURIComponent(dataStr);
    const date = new Date().toISOString().split('T')[0];
    const link = document.createElement('a');
    link.setAttribute('href', dataUri);
    link.setAttribute('download', `ANATOMY_MASTER_VAULT_${date}.json`);
    link.click();
  };

  const importVault = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const imported = JSON.parse(e.target?.result as string) as Question[];
        if (Array.isArray(imported)) {
          setUserVault(prev => {
            const currentMap = new Map(prev.map(q => [q.id, q]));
            imported.forEach(q => currentMap.set(q.id, q)); // Merge by ID
            return Array.from(currentMap.values());
          });
          alert("Vault Re-Synchronized: Import Successful.");
        }
      } catch (err) {
        alert("Integrity Error: File format corrupted.");
      }
    };
    reader.readAsText(file);
  };

  const clearUserData = () => {
    if (confirm("WARNING: This will delete all your custom questions, progress, and saved edits from the Local Vault. The core system questions will remain. Are you sure?")) {
      setUserVault([]);
      localStorage.removeItem('anatomy_ultimate_vault_v4');
      localStorage.removeItem('anatomy_quiz_session_v1');
      localStorage.removeItem('anatomy_quiz_mistakes_v1');
      window.location.reload();
    }
  };

  return (
    <div className="h-screen bg-slate-50 flex flex-col font-sans text-slate-900 selection:bg-blue-100 selection:text-blue-900 overflow-hidden">
      <Header 
        currentMode={currentMode} 
        onModeChange={setCurrentMode} 
      />

      {/* GLOBAL SYNC HUD */}
      <div className={`fixed bottom-12 right-12 z-[100] transition-all duration-700 pointer-events-none ${isSyncing ? 'translate-y-0 opacity-100' : 'translate-y-12 opacity-0'}`}>
        <div className="bg-slate-950 text-white px-8 py-4 rounded-[2rem] shadow-[0_20px_60px_rgba(0,0,0,0.3)] flex items-center gap-4 border border-slate-800">
          <div className="relative">
            <div className="absolute inset-0 bg-blue-500 rounded-full blur animate-ping opacity-50"></div>
            <DatabaseZap size={20} className="text-blue-400 relative z-10" />
          </div>
          <div className="flex flex-col">
            <span className="text-[10px] font-black uppercase tracking-[0.2em] text-blue-400">Knowledge Locked</span>
            <span className="text-[9px] font-bold text-slate-500 uppercase tracking-widest">Global Vault Synced</span>
          </div>
          <ShieldCheck size={20} className="text-emerald-400 ml-2" />
        </div>
      </div>

      <main className="flex-1 relative overflow-hidden">
        <div className={currentMode === AppMode.FLASHCARDS ? 'block h-full overflow-y-auto' : 'hidden'}>
          <div className="py-6">
            <Flashcards data={allQuestions} />
          </div>
        </div>
        <div className={currentMode === AppMode.QUIZ ? 'block h-full' : 'hidden'}>
          <Quiz data={allQuestions} />
        </div>
        <div className={currentMode === AppMode.LIST ? 'block h-full overflow-y-auto' : 'hidden'}>
          <div className="py-6">
            <QuestionList 
              data={allQuestions} 
              onExport={exportVault}
              onImport={importVault}
            />

            <div className="flex justify-center mt-12 mb-8">
               <button 
                 onClick={clearUserData}
                 className="flex items-center gap-2 text-xs font-bold text-red-400 hover:text-red-600 uppercase tracking-widest transition-colors opacity-60 hover:opacity-100"
               >
                 <Trash2 size={14} /> Factory Reset (Clear Local Vault)
               </button>
            </div>
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { Question, QuizQuestion } from '../types';
import Button from './Button';
import { 
  RotateCcw, 
  BrainCircuit, 
  Check, 
  X, 
  Clock, 
  Flag, 
  ChevronLeft, 
  ChevronRight, 
  LayoutGrid, 
  Image as ImageIcon, 
  Zap, 
  Hash, 
  Filter, 
  CheckCircle2,
  Lightbulb, 
  Shuffle,
  Maximize2,
  Play,
  Trophy,
  Target,
  Eye,
  List,
  Menu,
  BarChart3,
  AlertTriangle,
  ArrowRight,
  Medal,
  Share2
} from 'lucide-react';

const SESSION_KEY = 'anatomy_quiz_session_v1';
const SETTINGS_KEY = 'anatomy_quiz_settings_v1';
const MISTAKES_KEY = 'anatomy_quiz_mistakes_v1';

const formatTime = (seconds: number) => {
  const mins = Math.floor(seconds / 60);
  const secs = seconds % 60;
  return `${mins}:${secs.toString().padStart(2, '0')}`;
};

interface QuizProps {
  data: Question[];
}

const Quiz: React.FC<QuizProps> = ({ data }) => {
  const [view, setView] = useState<'setup' | 'playing' | 'results' | 'review'>('setup');
  const [mode, setMode] = useState<'exam' | 'practice' | 'mistakes'>('exam');
  const [questions, setQuestions] = useState<QuizQuestion[]>([]);
  const [currentQIndex, setCurrentQIndex] = useState(0);
  const [timeLeft, setTimeLeft] = useState(0);
  const [zoomedImage, setZoomedImage] = useState<string | null>(null);

  // Settings
  const [questionCount, setQuestionCount] = useState(25);
  const [selectedGroups, setSelectedGroups] = useState<string[]>([]);
  const [showImagesOnly, setShowImagesOnly] = useState(false);
  const [isDropdownOpen, setIsDropdownOpen] = useState(false);
  const [showExplanations, setShowExplanations] = useState(true);
  const [shuffleQuestions, setShuffleQuestions] = useState(true);

  // Mobile Nav State
  const [isMobileNavOpen, setIsMobileNavOpen] = useState(false);

  // History
  const [mistakesHistory, setMistakesHistory] = useState<string[]>([]);
  const [imgError, setImgError] = useState(false);

  useEffect(() => {
    // Load settings
    const savedSettings = localStorage.getItem(SETTINGS_KEY);
    if (savedSettings) {
      try {
        const parsed = JSON.parse(savedSettings);
        if (parsed.customQuestionCount) setQuestionCount(parsed.customQuestionCount);
        if (parsed.showImagesOnly !== undefined) setShowImagesOnly(parsed.showImagesOnly);
        if (parsed.selectedGroups) setSelectedGroups(parsed.selectedGroups);
        if (parsed.mode && parsed.mode !== 'mistakes') setMode(parsed.mode);
        if (parsed.showExplanations !== undefined) setShowExplanations(parsed.showExplanations);
        if (parsed.shuffleQuestions !== undefined) setShuffleQuestions(parsed.shuffleQuestions);
      } catch (e) {
        console.error("Failed to load settings", e);
      }
    }

    // Load active session
    const savedSession = localStorage.getItem(SESSION_KEY);
    if (savedSession) {
      try {
        const parsed = JSON.parse(savedSession);
        if ((parsed.status === 'playing' || parsed.status === 'review') && parsed.questions && parsed.questions.length > 0) {
          setQuestions(parsed.questions);
          setCurrentQIndex(parsed.currentQIndex || 0);
          setTimeLeft(parsed.timeLeft || 0);
          setMode(parsed.mode || 'exam');
          setView(parsed.status);
        }
      } catch (e) {
        console.error("Failed to load session", e);
      }
    }

    // Load mistakes
    const savedMistakes = localStorage.getItem(MISTAKES_KEY);
    if (savedMistakes) {
      try {
        setMistakesHistory(JSON.parse(savedMistakes));
      } catch (e) {
        console.error("Failed to load mistakes", e);
      }
    }
  }, []);

  useEffect(() => {
    const settings = {
      customQuestionCount: questionCount,
      showImagesOnly,
      selectedGroups,
      mode: mode === 'mistakes' ? 'exam' : mode,
      showExplanations,
      shuffleQuestions
    };
    localStorage.setItem(SETTINGS_KEY, JSON.stringify(settings));
  }, [questionCount, showImagesOnly, selectedGroups, mode, showExplanations, shuffleQuestions]);

  useEffect(() => {
    if (view === 'playing' || view === 'review') {
      const session = {
        questions,
        currentQIndex,
        timeLeft,
        status: view,
        mode
      };
      localStorage.setItem(SESSION_KEY, JSON.stringify(session));
    } else {
      localStorage.removeItem(SESSION_KEY);
    }
  }, [questions, currentQIndex, timeLeft, view, mode]);

  useEffect(() => {
    if (view === 'results') {
      const newMistakes = new Set(mistakesHistory);
      questions.forEach(q => {
        if (q.userAnswer === q.correctOption) {
          newMistakes.delete(q.id);
        } else {
          newMistakes.add(q.id);
        }
      });
      const updatedMistakes = Array.from(newMistakes);
      localStorage.setItem(MISTAKES_KEY, JSON.stringify(updatedMistakes));
      setMistakesHistory(updatedMistakes);
    }
  }, [view]);

  useEffect(() => {
    setImgError(false);
  }, [currentQIndex]);

  const availableGroups = useMemo(() => {
    const groups = new Set<string>();
    data.forEach(q => { if (q.category) groups.add(q.category); });
    return Array.from(groups).sort();
  }, [data]);

  const maxPossibleQuestions = useMemo(() => {
    let count = 0;
    data.forEach(q => {
      if (showImagesOnly && (!q.questionImage || q.questionImage.trim() === '')) return;
      if (!q.answerText || q.answerText.trim() === '') return;
      const cat = q.category || 'General';
      if (selectedGroups.length > 0 && !selectedGroups.includes(cat)) return;
      count++;
    });
    return count;
  }, [data, selectedGroups, showImagesOnly]);

  useEffect(() => {
    if (questionCount > maxPossibleQuestions && maxPossibleQuestions > 0) {
      setQuestionCount(maxPossibleQuestions);
    }
    if (maxPossibleQuestions === 0) setQuestionCount(0);
    else if (questionCount === 0 && maxPossibleQuestions > 0) setQuestionCount(1);
  }, [maxPossibleQuestions, questionCount]);

  const toggleGroup = (group: string) => {
    setSelectedGroups(prev => 
      prev.includes(group) ? prev.filter(g => g !== group) : [...prev, group]
    );
  };

  const toggleAllGroups = () => {
    if (selectedGroups.length === availableGroups.length) {
      setSelectedGroups([]);
    } else {
      setSelectedGroups([...availableGroups]);
    }
  };

  const generateQuiz = (pool: Question[], count: number) => {
    let selectedQuestions = [...pool];
    if (shuffleQuestions) {
        selectedQuestions.sort(() => Math.random() - 0.5);
    } else {
        selectedQuestions.sort((a, b) => a.id.localeCompare(b.id));
    }

    selectedQuestions = selectedQuestions.slice(0, count);

    return selectedQuestions.map(q => {
      const correct = q.answerText;
      let finalOptions: string[] = [];

      if (q.options && q.options.length > 0) {
        const uniqueOptions = Array.from(new Set(q.options));
        if (!uniqueOptions.includes(correct)) {
            uniqueOptions.push(correct);
        }
        const distractors = uniqueOptions
          .filter(opt => opt !== correct)
          .sort(() => Math.random() - 0.5);
        const selectedDistractors = distractors.slice(0, 3);
        finalOptions = [correct, ...selectedDistractors];
      }

      if (finalOptions.length < 4) {
        const categoryDistractors = Array.from(new Set(
          data
            .filter(i => i.category === q.category && i.answerText !== correct && i.answerText)
            .map(i => i.answerText)
        )) as string[];

        const generalDistractors = Array.from(new Set(
          data
            .filter(i => i.category !== q.category && i.answerText !== correct && i.answerText)
            .map(i => i.answerText)
        )) as string[];

        const existingSet = new Set(finalOptions);
        let needed = 4 - finalOptions.length;

        const validCatDistractors = categoryDistractors
          .filter(d => !existingSet.has(d))
          .sort(() => Math.random() - 0.5);

        const takenCat = validCatDistractors.slice(0, needed);
        finalOptions = [...finalOptions, ...takenCat];

        needed = 4 - finalOptions.length;
        if (needed > 0) {
             const validGenDistractors = generalDistractors
              .filter(d => !existingSet.has(d))
              .sort(() => Math.random() - 0.5);
             const takenGen = validGenDistractors.slice(0, needed);
             finalOptions = [...finalOptions, ...takenGen];
        }
      }

      finalOptions = finalOptions.sort(() => Math.random() - 0.5);

      return {
        id: q.id,
        data: q,
        options: finalOptions,
        correctOption: correct,
        userAnswer: null,
        isFlagged: false
      } as QuizQuestion;
    });
  };

  const startQuiz = () => {
    let pool = data.filter(q => q.answerText && q.answerText.trim() !== '');

    if (selectedGroups.length > 0) {
      pool = pool.filter(q => {
        const cat = q.category || 'General';
        return selectedGroups.includes(cat);
      });
    }

    if (showImagesOnly) {
      pool = pool.filter(q => q.questionImage && q.questionImage.trim() !== '');
    }

    if (pool.length === 0) {
      alert("No questions available matching your criteria.");
      return;
    }

    const count = Math.max(1, Math.min(questionCount, pool.length));
    const newQuestions = generateQuiz(pool, count);

    setQuestions(newQuestions);
    setCurrentQIndex(0);
    setTimeLeft(count * 60);
    setView('playing');
  };

  const startMistakesReview = () => {
    const pool = data.filter(q => mistakesHistory.includes(q.id));
    if (pool.length === 0) {
      alert("No mistakes found! Great job.");
      return;
    }

    setMode('mistakes');
    const newQuestions = generateQuiz(pool, pool.length);
    setQuestions(newQuestions);
    setCurrentQIndex(0);
    setTimeLeft(newQuestions.length * 60);
    setView('playing');
  };

  const clearMistakes = () => {
    if (confirm("Are you sure you want to clear your mistake history?")) {
      setMistakesHistory([]);
      localStorage.removeItem(MISTAKES_KEY);
    }
  };

  // Timer Tick Effect
  useEffect(() => {
    if ((view !== 'playing' && view !== 'review') || mode === 'practice') return;

    const timer = setInterval(() => {
      setTimeLeft(prev => Math.max(0, prev - 1));
    }, 1000);

    return () => clearInterval(timer);
  }, [view, mode]);

  // Timer Expiry Effect
  useEffect(() => {
    if (timeLeft === 0 && (view === 'playing' || view === 'review') && mode !== 'practice') {
      setView('results');
    }
  }, [timeLeft, view, mode]);

  const handleAnswer = (option: string) => {
    if (view === 'review') return;
    if (mode === 'practice' && questions[currentQIndex].userAnswer) return;

    setQuestions(prev => {
      const copy = [...prev];
      copy[currentQIndex].userAnswer = option;
      return copy;
    });
  };

  const toggleFlag = (index: number = currentQIndex) => {
    setQuestions(prev => {
      const copy = [...prev];
      copy[index].isFlagged = !copy[index].isFlagged;
      return copy;
    });
  };

  const calculateScore = () => {
    const correct = questions.filter(q => q.userAnswer === q.correctOption).length;
    return Math.round((correct / questions.length) * 100);
  };

  // Shared Modal for Zoom
  const ZoomModal = () => {
    if (!zoomedImage) return null;
    return (
      <div className="fixed inset-0 z-[100] bg-black/95 flex items-center justify-center p-4 animate-in fade-in duration-200" onClick={() => setZoomedImage(null)}>
        <button className="absolute top-4 right-4 text-white/70 hover:text-white p-2 transition-colors">
          <X size={32} />
        </button>
        <img 
          src={zoomedImage} 
          className="max-w-full max-h-full object-contain rounded-md shadow-2xl animate-in zoom-in-95 duration-300" 
          alt="Enlarged view" 
          onClick={(e) => e.stopPropagation()}
        />
      </div>
    );
  };

  // Setup View (No Changes to Setup)
  if (view === 'setup') {
    return (
      <div className="flex flex-col h-full bg-slate-50 overflow-y-auto">
        <div className="flex-1 flex flex-col items-center justify-center p-4 md:p-8 min-h-min">
          <div className="w-full max-w-4xl bg-white rounded-3xl shadow-xl border border-slate-200 overflow-hidden my-auto animate-in fade-in slide-in-from-bottom-4 duration-500">

            <div className="bg-slate-900 p-6 md:p-8 flex items-center justify-between border-b border-slate-800">
              <div>
                <h1 className="text-2xl md:text-3xl font-black text-white tracking-tight flex items-center gap-3">
                  <LayoutGrid className="text-blue-500" size={32} /> 
                  Assessment Setup
                </h1>
                <p className="text-slate-400 text-sm font-medium mt-1">Configure your session parameters.</p>
              </div>
              <div className="hidden sm:block text-right">
                 <div className="text-2xl font-black text-white">{maxPossibleQuestions}</div>
                 <div className="text-xs font-bold text-slate-500 uppercase tracking-widest">Questions</div>
              </div>
            </div>

            <div className="p-5 md:p-8 space-y-6 md:space-y-8">

              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                <button 
                  onClick={() => setMode('exam')}
                  className={`relative overflow-hidden p-5 rounded-2xl border-2 transition-all flex flex-col items-center justify-center text-center gap-3 group ${mode === 'exam' ? 'border-red-500 bg-red-50/50 shadow-lg shadow-red-100' : 'border-slate-200 hover:border-slate-300 hover:bg-slate-50'}`}
                >
                  <div className={`p-3 rounded-full ${mode === 'exam' ? 'bg-red-500 text-white' : 'bg-slate-100 text-slate-400 group-hover:bg-slate-200'}`}>
                    <Clock size={28} />
                  </div>
                  <div>
                    <div className={`font-black text-lg ${mode === 'exam' ? 'text-red-700' : 'text-slate-600'}`}>Exam Mode</div>
                    <div className="text-xs font-bold opacity-60 uppercase tracking-wider">Timed • Final Score</div>
                  </div>
                  {mode === 'exam' && <div className="absolute top-3 right-3 text-red-500"><CheckCircle2 size={20} /></div>}
                </button>

                <button 
                  onClick={() => setMode('practice')}
                  className={`relative overflow-hidden p-5 rounded-2xl border-2 transition-all flex flex-col items-center justify-center text-center gap-3 group ${mode === 'practice' ? 'border-blue-500 bg-blue-50/50 shadow-lg shadow-blue-100' : 'border-slate-200 hover:border-slate-300 hover:bg-slate-50'}`}
                >
                  <div className={`p-3 rounded-full ${mode === 'practice' ? 'bg-blue-500 text-white' : 'bg-slate-100 text-slate-400 group-hover:bg-slate-200'}`}>
                    <Zap size={28} />
                  </div>
                  <div>
                    <div className={`font-black text-lg ${mode === 'practice' ? 'text-blue-700' : 'text-slate-600'}`}>Practice Mode</div>
                    <div className="text-xs font-bold opacity-60 uppercase tracking-wider">Instant Feedback</div>
                  </div>
                  {mode === 'practice' && <div className="absolute top-3 right-3 text-blue-500"><CheckCircle2 size={20} /></div>}
                </button>
              </div>

              {mistakesHistory.length > 0 && (
                <div className="bg-amber-50 border-l-4 border-amber-400 rounded-r-xl p-4 flex flex-col sm:flex-row items-center justify-between shadow-sm gap-4">
                  <div className="flex items-center gap-4 w-full sm:w-auto">
                    <div className="bg-amber-100 p-2.5 rounded-full text-amber-600 shrink-0">
                      <BrainCircuit size={24} />
                    </div>
                    <div>
                      <h3 className="text-sm font-bold text-amber-900 uppercase tracking-wide">Review Needed</h3>
                      <p className="text-xs text-amber-700 font-medium">You have {mistakesHistory.length} questions queued for review.</p>
                    </div>
                  </div>
                  <div className="flex gap-2 w-full sm:w-auto">
                    <button onClick={startMistakesReview} className="flex-1 sm:flex-none flex items-center justify-center gap-2 px-5 py-2.5 bg-amber-500 hover:bg-amber-600 text-white text-xs font-bold uppercase rounded-lg shadow-md hover:shadow-lg transition-all active:scale-95">
                      <RotateCcw size={16} /> Review Now
                    </button>
                    <button onClick={clearMistakes} className="p-2.5 text-amber-600 hover:text-amber-800 hover:bg-amber-100 rounded-lg transition-colors" title="Clear history">
                      <X size={18} />
                    </button>
                  </div>
                </div>
              )}

              <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 md:gap-8">
                <div className="space-y-4 md:space-y-6">
                  <div className="flex justify-between items-center">
                    <label className="text-xs font-black text-slate-400 uppercase tracking-widest">Content Scope</label>
                    {selectedGroups.length > 0 && (
                      <button onClick={() => setSelectedGroups([])} className="text-[10px] font-bold text-red-500 hover:text-red-700 uppercase flex items-center gap-1 hover:bg-red-50 px-2 py-1 rounded transition-colors">
                        <X size={12} /> Clear
                      </button>
                    )}
                  </div>

                  <div className="relative">
                    <button 
                      onClick={() => setIsDropdownOpen(!isDropdownOpen)}
                      className={`w-full flex items-center justify-between p-4 rounded-xl border-2 transition-all shadow-sm ${isDropdownOpen ? 'border-blue-500 ring-4 ring-blue-50' : 'border-slate-200 bg-white hover:border-slate-300'}`}
                    >
                      <div className="flex items-center gap-3 text-slate-700 font-bold truncate">
                        <Filter size={20} className={selectedGroups.length > 0 ? "text-blue-500" : "text-slate-400"} />
                        <span className="truncate">{selectedGroups.length === 0 ? 'All Topics Included' : `${selectedGroups.length} Topics Selected`}</span>
                      </div>
                      {isDropdownOpen ? <ChevronLeft className="rotate-90 text-blue-500 shrink-0" size={20} /> : <ChevronRight className="rotate-90 text-slate-400 shrink-0" size={20} />}
                    </button>

                    {isDropdownOpen && (
                      <>
                        <div className="fixed inset-0 z-10" onClick={() => setIsDropdownOpen(false)}></div>
                        <div 
                          className="absolute top-full left-0 w-full mt-3 bg-white border border-slate-200 rounded-2xl shadow-2xl z-20 overflow-hidden animate-in fade-in slide-in-from-top-2 duration-200"
                          onClick={(e) => e.stopPropagation()} 
                        >
                          <div className="p-3 bg-slate-50 border-b border-slate-100 flex justify-between items-center">
                            <span className="text-xs font-bold text-slate-500 uppercase tracking-wider pl-2">Available Modules</span>
                            <button onClick={toggleAllGroups} className="text-xs font-bold text-blue-600 hover:text-blue-700 hover:bg-blue-50 px-3 py-1.5 rounded-lg transition-colors">
                              {selectedGroups.length === availableGroups.length ? 'Deselect All' : 'Select All'}
                            </button>
                          </div>
                          <div className="max-h-64 overflow-y-auto p-2 custom-scrollbar">
                            {availableGroups.map(group => (
                              <label key={group} className="flex items-center gap-3 p-3 hover:bg-slate-50 rounded-xl cursor-pointer group transition-colors">
                                <div className="checkbox-wrapper relative w-5 h-5 shrink-0">
                                  <input 
                                    type="checkbox" 
                                    className="peer appearance-none w-full h-full border-2 border-slate-300 rounded bg-white checked:bg-blue-600 checked:border-blue-600 transition-all cursor-pointer"
                                    checked={selectedGroups.includes(group)}
                                    onChange={() => toggleGroup(group)}
                                  />
                                  <Check size={14} className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-white pointer-events-none hidden peer-checked:block" />
                                </div>
                                <span className={`text-sm font-bold transition-colors ${selectedGroups.includes(group) ? 'text-slate-900' : 'text-slate-500 group-hover:text-slate-700'}`}>{group}</span>
                              </label>
                            ))}
                          </div>
                        </div>
                      </>
                    )}
                  </div>

                  {selectedGroups.length > 0 && (
                    <div className="flex flex-wrap gap-2 p-4 bg-slate-50 border border-slate-200 rounded-2xl max-h-32 overflow-y-auto custom-scrollbar shadow-inner">
                      {selectedGroups.map(group => (
                        <span key={group} className="inline-flex items-center gap-1.5 px-2.5 py-1 bg-white text-slate-700 text-xs font-bold rounded-md border border-slate-200 shadow-sm animate-in zoom-in-50 duration-200">
                          {group}
                          <button onClick={() => toggleGroup(group)} className="text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-full p-0.5 transition-colors">
                            <X size={12} />
                          </button>
                        </span>
                      ))}
                    </div>
                  )}
                </div>

                <div className="space-y-4 md:space-y-6">
                  <label className="text-xs font-black text-slate-400 uppercase tracking-widest">Configuration</label>

                  <div className="bg-slate-50 p-5 md:p-6 rounded-2xl border border-slate-200 space-y-5">
                    <div className="space-y-4">
                      <div className="flex justify-between items-center">
                        <div className="flex items-center gap-2 text-sm font-bold text-slate-700 uppercase tracking-wide">
                          <Hash size={16} className="text-blue-500" /> Quantity
                        </div>
                        <div className="flex items-center gap-2">
                           <input 
                              type="number" 
                              min="1" 
                              max={maxPossibleQuestions} 
                              value={questionCount}
                              onChange={(e) => {
                                const val = parseInt(e.target.value);
                                if (!isNaN(val)) {
                                  const safeVal = Math.min(Math.max(1, val), maxPossibleQuestions);
                                  setQuestionCount(safeVal);
                                }
                              }}
                              className="w-16 px-2 py-1 text-center font-black bg-white border border-slate-300 rounded-lg text-slate-800 outline-none focus:border-blue-500"
                            />
                            <span className="text-xs font-bold text-slate-400">/ {maxPossibleQuestions}</span>
                        </div>
                      </div>
                      <input 
                        type="range" 
                        min="1" 
                        max={maxPossibleQuestions} 
                        value={questionCount} 
                        onChange={(e) => setQuestionCount(parseInt(e.target.value))}
                        className="w-full accent-blue-600 h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer"
                      />
                    </div>

                    <div className="h-px bg-slate-200"></div>

                    <div className="space-y-3">
                      <button 
                        onClick={() => setShuffleQuestions(!shuffleQuestions)}
                        className="w-full flex items-center justify-between group"
                      >
                        <span className="font-bold text-xs text-slate-600 flex items-center gap-2 group-hover:text-purple-600 transition-colors">
                          <Shuffle size={16} /> Randomize Order
                        </span>
                        <div className={`w-10 h-5 rounded-full relative transition-colors ${shuffleQuestions ? 'bg-purple-600' : 'bg-slate-300'}`}>
                          <div className={`absolute top-1 w-3 h-3 rounded-full bg-white transition-all shadow-sm ${shuffleQuestions ? 'left-6' : 'left-1'}`}></div>
                        </div>
                      </button>

                      <button 
                        onClick={() => setShowImagesOnly(!showImagesOnly)}
                        className="w-full flex items-center justify-between group"
                      >
                        <span className="font-bold text-xs text-slate-600 flex items-center gap-2 group-hover:text-blue-600 transition-colors">
                          <ImageIcon size={16} /> Diagrams Only
                        </span>
                        <div className={`w-10 h-5 rounded-full relative transition-colors ${showImagesOnly ? 'bg-blue-600' : 'bg-slate-300'}`}>
                          <div className={`absolute top-1 w-3 h-3 rounded-full bg-white transition-all shadow-sm ${showImagesOnly ? 'left-6' : 'left-1'}`}></div>
                        </div>
                      </button>

                      <button 
                        onClick={() => setShowExplanations(!showExplanations)}
                        className="w-full flex items-center justify-between group"
                      >
                        <span className="font-bold text-xs text-slate-600 flex items-center gap-2 group-hover:text-amber-600 transition-colors">
                          <Lightbulb size={16} /> Enable Explanations
                        </span>
                        <div className={`w-10 h-5 rounded-full relative transition-colors ${showExplanations ? 'bg-amber-500' : 'bg-slate-300'}`}>
                          <div className={`absolute top-1 w-3 h-3 rounded-full bg-white transition-all shadow-sm ${showExplanations ? 'left-6' : 'left-1'}`}></div>
                        </div>
                      </button>
                    </div>
                  </div>
                </div>
              </div>

              <div className="pt-2">
                <Button 
                  variant="primary" 
                  onClick={startQuiz} 
                  fullWidth 
                  className="py-4 md:py-5 text-lg md:text-xl rounded-2xl shadow-xl shadow-blue-500/20 hover:shadow-blue-500/30 hover:-translate-y-1 active:translate-y-0 transition-all bg-gradient-to-r from-blue-600 to-indigo-700 border-none relative overflow-hidden group"
                  disabled={maxPossibleQuestions === 0}
                >
                  <div className="absolute inset-0 bg-white/20 translate-y-full group-hover:translate-y-0 transition-transform duration-300"></div>
                  <div className="relative flex items-center gap-3">
                    {maxPossibleQuestions === 0 ? (
                      'No Questions Match Filter'
                    ) : (
                      <>
                        <Play className="fill-current" size={24} />
                        Start {mode === 'exam' ? 'Exam' : 'Practice'} Session
                      </>
                    )}
                  </div>
                </Button>
                <p className="text-center text-xs font-bold text-slate-400 mt-4 uppercase tracking-widest">
                  {maxPossibleQuestions > 0 ? `Ready to launch with ${questionCount} questions` : 'Adjust filters to continue'}
                </p>
              </div>
            </div>
          </div>
        </div>
      </div>
    );
  }

  const currentQ = questions[currentQIndex];

  // --- NEW: SIDE NAVIGATION COMPONENT ---
  const QuestionNavigator = () => {
    const answeredCount = questions.filter(q => q.userAnswer).length;
    const unansweredCount = questions.length - answeredCount;

    return (
      <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden flex flex-col h-full max-h-[calc(100vh-8rem)]">
        <div className="p-4 border-b border-slate-100 bg-slate-50/50">
          <div className="flex items-center justify-between mb-4">
             <span className="text-xs font-black text-slate-400 uppercase tracking-widest">Session Status</span>
             <div className={`px-2.5 py-1 rounded-lg text-[10px] font-bold uppercase tracking-wide ${mode === 'exam' ? 'bg-red-50 text-red-600 border border-red-100' : 'bg-blue-50 text-blue-600 border border-blue-100'}`}>
                {mode === 'exam' ? 'Exam' : 'Practice'}
             </div>
          </div>

          <div className="flex items-center gap-3 mb-2">
             <div className="flex-1 bg-white border border-slate-200 rounded-xl p-2 text-center">
                <span className="block text-xs font-bold text-slate-400 uppercase">Time</span>
                <span className={`block font-mono font-black text-lg ${timeLeft < 60 ? 'text-red-500 animate-pulse' : 'text-slate-800'}`}>
                   {mode === 'practice' ? '--:--' : formatTime(timeLeft)}
                </span>
             </div>
             <div className="flex-1 bg-white border border-slate-200 rounded-xl p-2 text-center">
                <span className="block text-xs font-bold text-slate-400 uppercase">Solved</span>
                <span className="block font-mono font-black text-lg text-slate-800">
                   {answeredCount} <span className="text-slate-300 text-sm">/ {questions.length}</span>
                </span>
             </div>
          </div>
        </div>

        <div className="flex-1 overflow-y-auto custom-scrollbar p-3">
           <div className="grid grid-cols-5 gap-2">
              {questions.map((q, idx) => {
                 let statusClass = "bg-white border-slate-200 text-slate-600 hover:border-blue-300 hover:text-blue-600";
                 if (idx === currentQIndex) {
                    statusClass = "ring-2 ring-blue-500 border-blue-500 bg-blue-50 text-blue-700 z-10";
                 } else if (q.isFlagged) {
                    statusClass = "bg-amber-100 border-amber-300 text-amber-700";
                 } else if (q.userAnswer) {
                    statusClass = "bg-blue-600 border-blue-600 text-white";
                 }

                 return (
                    <button
                      key={q.id}
                      onClick={() => {
                        setCurrentQIndex(idx);
                        setIsMobileNavOpen(false);
                      }}
                      className={`aspect-square rounded-lg border-2 flex items-center justify-center text-xs font-bold transition-all relative ${statusClass}`}
                    >
                       {idx + 1}
                       {q.isFlagged && <div className="absolute top-0.5 right-0.5 w-1.5 h-1.5 bg-amber-500 rounded-full"></div>}
                    </button>
                 )
              })}
           </div>
        </div>

        {/* ACTIVE SUBMIT BUTTON */}
        <div className="p-4 border-t border-slate-100 bg-white space-y-2 sticky bottom-0 z-10 shadow-[0_-10px_20px_rgba(0,0,0,0.05)]">
             <button 
                onClick={() => {
                    if (view === 'review') {
                        if(confirm("Exit review mode and return to setup?")) {
                            setView('setup');
                            setIsMobileNavOpen(false);
                        }
                        return;
                    }

                    const msg = unansweredCount > 0 
                        ? `You have ${unansweredCount} unanswered questions. Are you sure you want to submit?` 
                        : "Ready to submit your exam?";

                    if (confirm(msg)) {
                        setView('results');
                        setIsMobileNavOpen(false);
                    }
                }}
                className={`w-full py-3.5 rounded-xl font-black uppercase tracking-widest transition-all flex items-center justify-center gap-2 shadow-lg text-xs transform active:scale-95 ${
                    view === 'review' 
                    ? 'bg-slate-100 text-slate-600 hover:bg-slate-200 border border-slate-200' 
                    : 'bg-slate-900 text-white hover:bg-slate-800 shadow-slate-900/20'
                }`}
            >
                {view === 'review' ? <LayoutGrid size={16} /> : <CheckCircle2 size={16} />}
                {view === 'review' ? 'End Review' : 'Submit Exam'}
            </button>
        </div>

        <div className="p-3 bg-slate-50 text-[10px] font-bold text-slate-400 flex justify-between gap-2 uppercase tracking-wide border-t border-slate-100">
           <div className="flex items-center gap-1"><div className="w-2 h-2 rounded-full bg-blue-600"></div>Done</div>
           <div className="flex items-center gap-1"><div className="w-2 h-2 rounded-full bg-amber-400"></div>Flag</div>
           <div className="flex items-center gap-1"><div className="w-2 h-2 rounded-full border-2 border-slate-300"></div>Open</div>
        </div>
      </div>
    )
  }

  // Combined Playing/Review View
  if (view === 'playing' || view === 'review') {
    return (
      <div className="h-[calc(100vh-5rem)] flex flex-col w-full bg-slate-50 relative overflow-hidden">
        <ZoomModal />

        {/* Mobile Nav Drawer */}
        {isMobileNavOpen && (
          <div className="absolute inset-0 z-50 bg-slate-900/50 backdrop-blur-sm lg:hidden" onClick={() => setIsMobileNavOpen(false)}>
             <div className="absolute right-0 top-0 bottom-0 w-72 bg-white shadow-2xl animate-in slide-in-from-right duration-300" onClick={e => e.stopPropagation()}>
                <QuestionNavigator />
             </div>
          </div>
        )}

        <div className="max-w-[1400px] mx-auto w-full h-full p-4 flex gap-6">

           {/* MAIN CONTENT AREA */}
           <div className="flex-1 flex flex-col h-full gap-4 min-w-0">

              {/* Toolbar */}
              <div className="flex justify-between items-center bg-white p-3 rounded-2xl border border-slate-200 shadow-sm shrink-0">
                 <div className="flex items-center gap-4">
                    <span className="px-3 py-1 bg-slate-900 text-white rounded-lg text-xs font-black uppercase tracking-wider">
                       Question {currentQIndex + 1}
                    </span>
                    <span className="text-xs font-bold text-slate-500 truncate hidden sm:block max-w-xs">
                       {currentQ.data.category}
                    </span>
                 </div>

                 <div className="flex items-center gap-2">
                    <button 
                      onClick={() => setIsMobileNavOpen(true)}
                      className="lg:hidden p-2 rounded-lg bg-slate-50 border border-slate-200 text-slate-600"
                    >
                       <List size={20} />
                    </button>
                    <button 
                      onClick={() => toggleFlag()}
                      className={`p-2 rounded-lg border transition-all flex items-center gap-2 text-xs font-bold ${currentQ.isFlagged ? 'bg-amber-100 border-amber-200 text-amber-700' : 'bg-white border-slate-200 text-slate-400 hover:text-amber-500'}`}
                    >
                      <Flag size={16} className={currentQ.isFlagged ? "fill-current" : ""} />
                      <span className="hidden sm:inline">Flag for Review</span>
                    </button>
                    <button 
                      onClick={() => {
                        if (confirm('End session and return to setup? Progress will be lost.')) {
                          setView('setup');
                          localStorage.removeItem(SESSION_KEY);
                        }
                      }}
                      className="p-2 rounded-lg bg-white border border-slate-200 text-slate-400 hover:text-red-500 hover:bg-red-50 transition-colors"
                    >
                      <X size={20} />
                    </button>
                 </div>
              </div>

              {/* Question Card */}
              <div className="flex-1 bg-white rounded-3xl border border-slate-200 shadow-sm overflow-hidden flex flex-col relative">
                 <div className="flex-1 overflow-y-auto custom-scrollbar p-6 md:p-10">
                    <div className="max-w-4xl mx-auto space-y-8">

                       {/* Question Text */}
                       <div className="text-xl md:text-2xl font-medium text-slate-900 leading-relaxed">
                          <span dangerouslySetInnerHTML={{ __html: currentQ.data.questionText }} />
                       </div>

                       {/* Image */}
                       {currentQ.data.questionImage && !imgError && (
                          <div 
                            className="w-full bg-slate-50 rounded-2xl border-2 border-slate-100 p-4 flex justify-center cursor-zoom-in hover:border-blue-200 transition-colors group"
                            onClick={() => setZoomedImage(currentQ.data.questionImage!)}
                          >
                             <img 
                               src={currentQ.data.questionImage} 
                               className="max-h-[40vh] object-contain mix-blend-multiply"
                               onError={() => setImgError(true)}
                               alt="Question Diagram"
                             />
                             <div className="absolute top-4 right-4 bg-white shadow-sm p-2 rounded-lg opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none">
                                <Maximize2 size={16} className="text-slate-500" />
                             </div>
                          </div>
                       )}

                       {/* Options Grid */}
                       <div className="grid grid-cols-1 gap-3">
                          {currentQ.options.map((option, idx) => {
                            const isSelected = currentQ.userAnswer === option;
                            const isCorrect = option === currentQ.correctOption;
                            const showResult = view === 'review' || (mode === 'practice' && !!currentQ.userAnswer);

                            let btnClass = "border-2 border-slate-100 hover:border-blue-300 hover:bg-slate-50";
                            let icon = <div className="w-6 h-6 rounded-md border-2 border-slate-300 flex items-center justify-center text-xs font-bold text-slate-400 group-hover:border-blue-400 group-hover:text-blue-500">{String.fromCharCode(65 + idx)}</div>;

                            if (showResult) {
                              if (isCorrect) {
                                 btnClass = "border-emerald-500 bg-emerald-50 ring-1 ring-emerald-500";
                                 icon = <div className="w-6 h-6 rounded-md bg-emerald-500 text-white flex items-center justify-center"><Check size={14} /></div>;
                              } else if (isSelected) {
                                 btnClass = "border-red-500 bg-red-50 ring-1 ring-red-500";
                                 icon = <div className="w-6 h-6 rounded-md bg-red-500 text-white flex items-center justify-center"><X size={14} /></div>;
                              } else {
                                 btnClass = "border-slate-100 opacity-50 grayscale";
                              }
                            } else if (isSelected) {
                              btnClass = "border-blue-600 bg-blue-50 ring-1 ring-blue-600";
                              icon = <div className="w-6 h-6 rounded-md bg-blue-600 text-white flex items-center justify-center font-bold">{String.fromCharCode(65 + idx)}</div>;
                            }

                            return (
                              <button
                                key={idx}
                                onClick={() => handleAnswer(option)}
                                disabled={showResult}
                                className={`w-full p-4 rounded-xl text-left transition-all duration-200 flex items-start gap-4 group ${btnClass}`}
                              >
                                <div className="mt-0.5 shrink-0">{icon}</div>
                                <div className={`text-base md:text-lg font-medium ${isSelected || (showResult && isCorrect) ? 'text-slate-900' : 'text-slate-600'}`}>
                                   <span dangerouslySetInnerHTML={{ __html: option }} />
                                </div>
                              </button>
                            );
                          })}
                       </div>

                       {/* Explanation */}
                       {(view === 'review' || (mode === 'practice' && currentQ.userAnswer && showExplanations)) && (
                          <div className="animate-in fade-in slide-in-from-top-4 duration-500">
                             <div className={`p-6 rounded-2xl border-l-4 ${currentQ.userAnswer === currentQ.correctOption ? 'bg-emerald-50 border-emerald-500' : 'bg-amber-50 border-amber-500'}`}>
                                <h4 className="flex items-center gap-2 text-sm font-black uppercase tracking-widest mb-3 opacity-70">
                                   <Lightbulb size={18} /> Rationale
                                </h4>
                                <div className="prose prose-sm prose-slate max-w-none">
                                   {currentQ.data.explanation ? (
                                      <span dangerouslySetInnerHTML={{ __html: currentQ.data.explanation }} />
                                   ) : (
                                      <span className="italic opacity-60">No specific explanation provided for this question.</span>
                                   )}
                                </div>
                                {currentQ.data.answerImage && (
                                   <div className="mt-4">
                                      <button 
                                        onClick={() => setZoomedImage(currentQ.data.answerImage!)}
                                        className="text-xs font-bold text-blue-600 flex items-center gap-2 hover:underline"
                                      >
                                         <ImageIcon size={14} /> View Detailed Diagram
                                      </button>
                                   </div>
                                )}
                             </div>
                          </div>
                       )}
                    </div>
                 </div>

                 {/* Footer Navigation */}
                 <div className="p-4 border-t border-slate-100 bg-white flex justify-between items-center gap-4">
                    <button 
                      onClick={() => setCurrentQIndex(prev => prev - 1)}
                      disabled={currentQIndex === 0}
                      className="px-6 py-3 rounded-xl font-bold text-slate-500 hover:bg-slate-100 hover:text-slate-900 disabled:opacity-30 disabled:hover:bg-transparent transition-colors flex items-center gap-2"
                    >
                       <ChevronLeft size={20} /> Previous
                    </button>

                    {currentQIndex === questions.length - 1 ? (
                      <button 
                        onClick={() => setView('results')}
                        className="px-8 py-3 rounded-xl bg-slate-900 text-white font-bold hover:bg-blue-600 shadow-lg shadow-blue-500/20 transition-all flex items-center gap-2"
                      >
                        {view === 'review' ? 'Return to Dashboard' : 'Submit Exam'} <CheckCircle2 size={18} />
                      </button>
                    ) : (
                      <button 
                        onClick={() => setCurrentQIndex(prev => prev + 1)}
                        className="px-8 py-3 rounded-xl bg-blue-600 text-white font-bold hover:bg-blue-700 shadow-lg shadow-blue-500/20 transition-all flex items-center gap-2"
                      >
                        Next Question <ChevronRight size={20} />
                      </button>
                    )}
                 </div>
              </div>
           </div>

           {/* DESKTOP SIDEBAR */}
           <div className="hidden lg:block w-80 shrink-0">
              <QuestionNavigator />
           </div>

        </div>
      </div>
    );
  }

  // Results View
  if (view === 'results') {
    const totalQuestions = questions.length;
    const correctCount = questions.filter(q => q.userAnswer === q.correctOption).length;
    const incorrectCount = questions.filter(q => q.userAnswer && q.userAnswer !== q.correctOption).length;
    const skippedCount = totalQuestions - correctCount - incorrectCount;
    const score = Math.round((correctCount / totalQuestions) * 100);
    const isPassing = score >= 70;

    return (
      <div className="flex flex-col h-full bg-slate-50 overflow-y-auto">
        <div className="max-w-4xl mx-auto w-full my-8 p-6 animate-in fade-in slide-in-from-bottom-8 duration-700">

           {/* Header Card */}
           <div className="bg-white rounded-[2.5rem] shadow-2xl overflow-hidden border border-slate-200">

              {/* Score Hero Section */}
              <div className={`${isPassing ? 'bg-emerald-600' : 'bg-slate-900'} p-12 text-center relative overflow-hidden`}>
                  <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/cubes.png')] opacity-10"></div>

                  <div className="relative z-10 flex flex-col items-center">
                      <div className="inline-flex p-6 rounded-full bg-white/10 backdrop-blur-md mb-8 shadow-2xl ring-1 ring-white/20">
                        {isPassing ? <Trophy size={64} className="text-white" strokeWidth={1.5} /> : <Target size={64} className="text-white" strokeWidth={1.5} />}
                      </div>

                      <div className="space-y-2 mb-8">
                        <h2 className="text-8xl font-black text-white tracking-tighter leading-none">{score}<span className="text-4xl align-top opacity-60">%</span></h2>
                        <div className="flex items-center justify-center gap-2 opacity-80">
                           <Medal size={16} className="text-white" />
                           <span className="text-sm font-bold text-white uppercase tracking-widest">{isPassing ? 'Certified Excellence' : 'Needs Improvement'}</span>
                        </div>
                      </div>

                      <p className="max-w-md mx-auto text-white/90 font-medium text-lg leading-relaxed">
                        {isPassing 
                          ? "Outstanding performance. You've demonstrated strong command of the material." 
                          : "Keep pushing. Review the material below to strengthen your understanding."}
                      </p>
                  </div>
              </div>

              {/* Detailed Stats Grid */}
              <div className="grid grid-cols-3 divide-x divide-slate-100 border-b border-slate-100 bg-white">
                 <div className="p-8 text-center hover:bg-slate-50 transition-colors group">
                    <span className="block text-5xl font-black text-emerald-500 mb-2 group-hover:scale-110 transition-transform">{correctCount}</span>
                    <span className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] flex items-center justify-center gap-2">
                       <CheckCircle2 size={12} className="text-emerald-500" /> Correct
                    </span>
                 </div>
                 <div className="p-8 text-center hover:bg-slate-50 transition-colors group">
                    <span className="block text-5xl font-black text-rose-500 mb-2 group-hover:scale-110 transition-transform">{incorrectCount}</span>
                    <span className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] flex items-center justify-center gap-2">
                       <AlertTriangle size={12} className="text-rose-500" /> Incorrect
                    </span>
                 </div>
                 <div className="p-8 text-center hover:bg-slate-50 transition-colors group">
                    <span className="block text-5xl font-black text-slate-400 mb-2 group-hover:scale-110 transition-transform">{skippedCount}</span>
                    <span className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] flex items-center justify-center gap-2">
                       <Hash size={12} /> Skipped
                    </span>
                 </div>
              </div>

              {/* Action Menu */}
              <div className="p-10 bg-slate-50/50 space-y-8">
                  <div className="flex flex-col gap-4">
                      <button 
                        onClick={() => {
                          setView('review');
                          setCurrentQIndex(0);
                        }}
                        className="w-full py-5 rounded-2xl bg-slate-900 text-white font-black text-lg uppercase tracking-widest hover:bg-blue-600 hover:shadow-xl hover:-translate-y-1 transition-all flex items-center justify-center gap-3 shadow-lg shadow-slate-900/10 group"
                      >
                        <Eye size={24} className="group-hover:scale-110 transition-transform" /> Review Full Exam
                      </button>

                      {incorrectCount > 0 && (
                        <button 
                          onClick={() => {
                             const mistakes = questions.filter(q => q.userAnswer !== q.correctOption);
                             const newMistakes = mistakes.map(q => ({...q, userAnswer: null, isFlagged: false}));
                             setQuestions(newMistakes);
                             setCurrentQIndex(0);
                             setTimeLeft(newMistakes.length * 60);
                             setView('playing');
                          }}
                          className="w-full py-5 rounded-2xl bg-white border-2 border-rose-100 text-rose-600 font-black text-lg uppercase tracking-widest hover:bg-rose-50 hover:border-rose-200 transition-all flex items-center justify-center gap-3 shadow-sm group"
                        >
                          <BrainCircuit size={24} className="group-hover:rotate-12 transition-transform" /> Practice Mistakes ({incorrectCount})
                        </button>
                      )}
                  </div>

                  <div className="grid grid-cols-2 gap-4 pt-4 border-t border-slate-200">
                      <button 
                        onClick={() => {
                          const retryQs = questions.map(q => ({...q, userAnswer: null, isFlagged: false}));
                          setQuestions(retryQs);
                          setCurrentQIndex(0);
                          setTimeLeft(questions.length * 60);
                          setView('playing');
                        }}
                        className="py-4 rounded-xl font-bold text-slate-600 hover:bg-white hover:shadow-md transition-all flex items-center justify-center gap-2 border border-transparent hover:border-slate-200"
                      >
                        <RotateCcw size={18} /> Retry Same Set
                      </button>

                      <button 
                        onClick={() => {
                          setView('setup');
                          localStorage.removeItem(SESSION_KEY);
                        }}
                        className="py-4 rounded-xl font-bold text-slate-600 hover:bg-white hover:shadow-md transition-all flex items-center justify-center gap-2 border border-transparent hover:border-slate-200"
                      >
                        <LayoutGrid size={18} /> New Session
                      </button>
                  </div>
              </div>
           </div>
        </div>
      </div>
    );
  }

  return null;
};

export default Quiz;

import React, { useState, useEffect, useMemo } from 'react';
import { Question, QuizQuestion } from '../types';
import Button from './Button';
import { 
  RotateCcw, 
  BrainCircuit, 
  Check, 
  X, 
  Clock, 
  Flag, 
  ChevronLeft, 
  ChevronRight, 
  LayoutGrid, 
  Image as ImageIcon, 
  Zap, 
  Hash, 
  Filter, 
  CheckCircle2,
  Lightbulb, 
  Shuffle,
  Maximize2,
  Play,
  Trophy,
  Target,
  Eye,
  List,
  BarChart3,
  AlertTriangle,
  Medal
} from 'lucide-react';

const SESSION_KEY = 'anatomy_quiz_session_v1';
const SETTINGS_KEY = 'anatomy_quiz_settings_v1';
const MISTAKES_KEY = 'anatomy_quiz_mistakes_v1';

const formatTime = (seconds: number) => {
  const mins = Math.floor(seconds / 60);
  const secs = seconds % 60;
  return `${mins}:${secs.toString().padStart(2, '0')}`;
};

interface QuizProps {
  data: Question[];
}

const Quiz: React.FC<QuizProps> = ({ data }) => {
  const [view, setView] = useState<'setup' | 'playing' | 'results' | 'review'>('setup');
  const [mode, setMode] = useState<'exam' | 'practice' | 'mistakes'>('exam');
  const [questions, setQuestions] = useState<QuizQuestion[]>([]);
  const [currentQIndex, setCurrentQIndex] = useState(0);
  const [timeLeft, setTimeLeft] = useState(0);
  const [zoomedImage, setZoomedImage] = useState<string | null>(null);

  // Settings
  const [questionCount, setQuestionCount] = useState(25);
  const [selectedGroups, setSelectedGroups] = useState<string[]>([]);
  const [showImagesOnly, setShowImagesOnly] = useState(false);
  const [isDropdownOpen, setIsDropdownOpen] = useState(false);
  const [showExplanations, setShowExplanations] = useState(true);
  const [shuffleQuestions, setShuffleQuestions] = useState(true);

  // Mobile Nav State
  const [isMobileNavOpen, setIsMobileNavOpen] = useState(false);

  // History
  const [mistakesHistory, setMistakesHistory] = useState<string[]>([]);
  const [imgError, setImgError] = useState(false);

  useEffect(() => {
    // Load settings
    const savedSettings = localStorage.getItem(SETTINGS_KEY);
    if (savedSettings) {
      try {
        const parsed = JSON.parse(savedSettings);
        if (parsed.customQuestionCount) setQuestionCount(parsed.customQuestionCount);
        if (parsed.showImagesOnly !== undefined) setShowImagesOnly(parsed.showImagesOnly);
        if (parsed.selectedGroups) setSelectedGroups(parsed.selectedGroups);
        if (parsed.mode && parsed.mode !== 'mistakes') setMode(parsed.mode);
        if (parsed.showExplanations !== undefined) setShowExplanations(parsed.showExplanations);
        if (parsed.shuffleQuestions !== undefined) setShuffleQuestions(parsed.shuffleQuestions);
      } catch (e) {
        console.error("Failed to load settings", e);
      }
    }

    // Load active session
    const savedSession = localStorage.getItem(SESSION_KEY);
    if (savedSession) {
      try {
        const parsed = JSON.parse(savedSession);
        if ((parsed.status === 'playing' || parsed.status === 'review') && parsed.questions && parsed.questions.length > 0) {
          setQuestions(parsed.questions);
          setCurrentQIndex(parsed.currentQIndex || 0);
          setTimeLeft(parsed.timeLeft || 0);
          setMode(parsed.mode || 'exam');
          setView(parsed.status);
        }
      } catch (e) {
        console.error("Failed to load session", e);
      }
    }

    // Load mistakes
    const savedMistakes = localStorage.getItem(MISTAKES_KEY);
    if (savedMistakes) {
      try {
        setMistakesHistory(JSON.parse(savedMistakes));
      } catch (e) {
        console.error("Failed to load mistakes", e);
      }
    }
  }, []);

  useEffect(() => {
    const settings = {
      customQuestionCount: questionCount,
      showImagesOnly,
      selectedGroups,
      mode: mode === 'mistakes' ? 'exam' : mode,
      showExplanations,
      shuffleQuestions
    };
    localStorage.setItem(SETTINGS_KEY, JSON.stringify(settings));
  }, [questionCount, showImagesOnly, selectedGroups, mode, showExplanations, shuffleQuestions]);

  useEffect(() => {
    if (view === 'playing' || view === 'review') {
      const session = {
        questions,
        currentQIndex,
        timeLeft,
        status: view,
        mode
      };
      localStorage.setItem(SESSION_KEY, JSON.stringify(session));
    } else {
      localStorage.removeItem(SESSION_KEY);
    }
  }, [questions, currentQIndex, timeLeft, view, mode]);

  useEffect(() => {
    if (view === 'results') {
      const newMistakes = new Set(mistakesHistory);
      questions.forEach(q => {
        if (q.userAnswer === q.correctOption) {
          newMistakes.delete(q.id);
        } else {
          newMistakes.add(q.id);
        }
      });
      const updatedMistakes = Array.from(newMistakes);
      localStorage.setItem(MISTAKES_KEY, JSON.stringify(updatedMistakes));
      setMistakesHistory(updatedMistakes);
    }
  }, [view]);

  useEffect(() => {
    setImgError(false);
  }, [currentQIndex]);

  const availableGroups = useMemo(() => {
    const groups = new Set<string>();
    data.forEach(q => { if (q.category) groups.add(q.category); });
    return Array.from(groups).sort();
  }, [data]);

  const maxPossibleQuestions = useMemo(() => {
    let count = 0;
    data.forEach(q => {
      if (showImagesOnly && (!q.questionImage || q.questionImage.trim() === '')) return;
      if (!q.answerText || q.answerText.trim() === '') return;
      const cat = q.category || 'General';
      if (selectedGroups.length > 0 && !selectedGroups.includes(cat)) return;
      count++;
    });
    return count;
  }, [data, selectedGroups, showImagesOnly]);

  useEffect(() => {
    if (questionCount > maxPossibleQuestions && maxPossibleQuestions > 0) {
      setQuestionCount(maxPossibleQuestions);
    }
    if (maxPossibleQuestions === 0) setQuestionCount(0);
    else if (questionCount === 0 && maxPossibleQuestions > 0) setQuestionCount(1);
  }, [maxPossibleQuestions, questionCount]);

  const toggleGroup = (group: string) => {
    setSelectedGroups(prev => 
      prev.includes(group) ? prev.filter(g => g !== group) : [...prev, group]
    );
  };

  const toggleAllGroups = () => {
    if (selectedGroups.length === availableGroups.length) {
      setSelectedGroups([]);
    } else {
      setSelectedGroups([...availableGroups]);
    }
  };

  const generateQuiz = (pool: Question[], count: number) => {
    let selectedQuestions = [...pool];
    if (shuffleQuestions) {
        selectedQuestions.sort(() => Math.random() - 0.5);
    } else {
        selectedQuestions.sort((a, b) => a.id.localeCompare(b.id));
    }

    selectedQuestions = selectedQuestions.slice(0, count);

    return selectedQuestions.map(q => {
      const correct = q.answerText;
      let finalOptions: string[] = [];

      if (q.options && q.options.length > 0) {
        const uniqueOptions = Array.from(new Set(q.options));
        if (!uniqueOptions.includes(correct)) {
            uniqueOptions.push(correct);
        }
        const distractors = uniqueOptions
          .filter(opt => opt !== correct)
          .sort(() => Math.random() - 0.5);
        const selectedDistractors = distractors.slice(0, 3);
        finalOptions = [correct, ...selectedDistractors];
      }

      if (finalOptions.length < 4) {
        const categoryDistractors = Array.from(new Set(
          data
            .filter(i => i.category === q.category && i.answerText !== correct && i.answerText)
            .map(i => i.answerText)
        )) as string[];

        const generalDistractors = Array.from(new Set(
          data
            .filter(i => i.category !== q.category && i.answerText !== correct && i.answerText)
            .map(i => i.answerText)
        )) as string[];

        const existingSet = new Set(finalOptions);
        let needed = 4 - finalOptions.length;

        const validCatDistractors = categoryDistractors
          .filter(d => !existingSet.has(d))
          .sort(() => Math.random() - 0.5);

        const takenCat = validCatDistractors.slice(0, needed);
        finalOptions = [...finalOptions, ...takenCat];

        needed = 4 - finalOptions.length;
        if (needed > 0) {
             const validGenDistractors = generalDistractors
              .filter(d => !existingSet.has(d))
              .sort(() => Math.random() - 0.5);
             const takenGen = validGenDistractors.slice(0, needed);
             finalOptions = [...finalOptions, ...takenGen];
        }
      }

      finalOptions = finalOptions.sort(() => Math.random() - 0.5);

      return {
        id: q.id,
        data: q,
        options: finalOptions,
        correctOption: correct,
        userAnswer: null,
        isFlagged: false
      } as QuizQuestion;
    });
  };

  const startQuiz = () => {
    let pool = data.filter(q => q.answerText && q.answerText.trim() !== '');

    if (selectedGroups.length > 0) {
      pool = pool.filter(q => {
        const cat = q.category || 'General';
        return selectedGroups.includes(cat);
      });
    }

    if (showImagesOnly) {
      pool = pool.filter(q => q.questionImage && q.questionImage.trim() !== '');
    }

    if (pool.length === 0) {
      alert("No questions available matching your criteria.");
      return;
    }

    const count = Math.max(1, Math.min(questionCount, pool.length));
    const newQuestions = generateQuiz(pool, count);

    setQuestions(newQuestions);
    setCurrentQIndex(0);
    setTimeLeft(count * 60);
    setView('playing');
  };

  const startMistakesReview = () => {
    const pool = data.filter(q => mistakesHistory.includes(q.id));
    if (pool.length === 0) {
      alert("No mistakes found! Great job.");
      return;
    }

    setMode('mistakes');
    const newQuestions = generateQuiz(pool, pool.length);
    setQuestions(newQuestions);
    setCurrentQIndex(0);
    setTimeLeft(newQuestions.length * 60);
    setView('playing');
