             <div className={`px-2.5 py-1 rounded-lg text-[10px] font-bold uppercase tracking-wide ${mode === 'exam' ? 'bg-red-50 text-red-600 border border-red-100' : 'bg-blue-50 text-blue-600 border border-blue-100'}`}>
