import React, { useState, useEffect, useRef, useCallback } from 'react';

type AudioType = 'question' | 'answer' | 'explanation' | 'generic';

export const useSpeech = () => {
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [speakingId, setSpeakingId] = useState<string | null>(null);
  const [activeType, setActiveType] = useState<AudioType | null>(null);
  const [voice, setVoice] = useState<SpeechSynthesisVoice | null>(null);

  const speakingRef = useRef<boolean>(false);
  const activeUtteranceId = useRef<string | null>(null);

  const loadVoices = useCallback(() => {
    if (typeof window === 'undefined' || !window.speechSynthesis) return;

    let voices = window.speechSynthesis.getVoices();
    if (voices.length === 0) return;

    // Strict Priority List for High-Quality Natural Female Voices
    const preferred = 
      // 1. Premium Neural Female (Edge/Modern Windows)
      voices.find(v => v.name.includes('Aria') && v.name.includes('Natural')) ||
      voices.find(v => v.name.includes('Jenny') && v.name.includes('Natural')) ||

      // 2. Google High-Quality Female (Chrome)
      voices.find(v => v.name === 'Google US English' && v.lang === 'en-US') ||
      voices.find(v => v.name.includes('Female') && v.name.includes('Google')) ||

      // 3. Apple/Safari Professional Female
      voices.find(v => v.name === 'Samantha') || 
      voices.find(v => v.name === 'Nicky') ||

      // 4. Windows Classic Professional
      voices.find(v => v.name.includes('Zira')) ||

      // 5. Fallback: Any English Female voice
      voices.find(v => v.lang.startsWith('en') && v.name.toLowerCase().includes('female')) ||

      // 6. Absolute Fallback (First English voice)
      voices.find(v => v.lang.startsWith('en'));

    setVoice(preferred || null);
  }, []);

  useEffect(() => {
    loadVoices();
    if (window.speechSynthesis && window.speechSynthesis.onvoiceschanged !== undefined) {
      window.speechSynthesis.onvoiceschanged = loadVoices;
    }
    return () => {
      if (typeof window !== 'undefined' && window.speechSynthesis) {
        window.speechSynthesis.cancel();
      }
    };
  }, [loadVoices]);

  const cancel = useCallback(() => {
    if (typeof window !== 'undefined' && window.speechSynthesis) {
      window.speechSynthesis.cancel();
      setIsSpeaking(false);
      setSpeakingId(null);
      setActiveType(null);
      speakingRef.current = false;
      activeUtteranceId.current = null;
    }
  }, []);

  const speak = useCallback((text: string, id: string, type: AudioType = 'generic', e?: React.MouseEvent | React.KeyboardEvent) => {
    if (e) e.stopPropagation();
    if (typeof window === 'undefined' || !window.speechSynthesis) return;

    if (speakingRef.current && activeUtteranceId.current === id) {
      cancel();
      return;
    }

    cancel();

    // Superior Text Cleaning for Medical Terminology
    const cleanText = text
      .replace(/<[^>]*>/g, '') // Strip all HTML
      .replace(/\//g, ' or ')
      .replace(/&/g, ' and ')
      .replace(/Ca2\+/g, 'calcium ions') // Specific medical fix
      .replace(/Na\+/g, 'sodium ions')   // Specific medical fix
      .replace(/H\+/g, 'hydrogen ions') // Specific medical fix
      .replace(/ATP/g, 'A T P')          // Force acronym pronunciation
      .replace(/RNA/g, 'R N A')
      .replace(/DNA/g, 'D N A')
      .replace(/([.:;?!])/g, '$1 ') 
      .replace(/[\(\[\{]/g, ', ') 
      .replace(/[\)\]\}]/g, ', ');

    // Precise Chunking for natural breathing pauses
    const chunks = cleanText.match(/[^.!?]+[.!?]+(?=\s|$)|[^.!?]+$/g) || [cleanText];
    const filteredChunks = chunks.map(c => c.trim()).filter(c => c.length > 0);

    if (filteredChunks.length === 0) return;

    activeUtteranceId.current = id;
    speakingRef.current = true;
    setIsSpeaking(true);
    setSpeakingId(id);
    setActiveType(type);

    filteredChunks.forEach((chunk, index) => {
      const utterance = new SpeechSynthesisUtterance(chunk);

      if (voice) {
        utterance.voice = voice;
        utterance.lang = voice.lang;
      } else {
        utterance.lang = 'en-US';
      }

      // Clarity Optimization
      utterance.rate = 0.85;  // Slightly slower for medical precision
      utterance.pitch = 1.05; // Slightly higher for clear female tone
      utterance.volume = 1.0;

      if (index === filteredChunks.length - 1) {
        utterance.onend = () => {
          if (activeUtteranceId.current === id) {
            setIsSpeaking(false);
            setSpeakingId(null);
            setActiveType(null);
            speakingRef.current = false;
            activeUtteranceId.current = null;
          }
        };
      }

      utterance.onerror = () => {
        if (activeUtteranceId.current === id) {
          setIsSpeaking(false);
          setSpeakingId(null);
          speakingRef.current = false;
        }
      };

      window.speechSynthesis.speak(utterance);
    });

  }, [voice, cancel]);

  return {
    speak,
    cancel,
    isSpeaking,
    speakingId,
    activeType,
    hasSupport: typeof window !== 'undefined' && 'speechSynthesis' in window
  };
};

